There are two issues here; the first is a problem in your alias hierarchy, the second is an issue with how pybind handles alias classes.

The alias hierarchy needs to mirror the main class hierarchy, and *then* inherit from the main classes.  Right now, your main classes are:
```
objbase   iface
     \    /
     mytype
```
but your alias hierarchy for mytype and objcase are, respectively:
```
objbase    iface                objbase
     \     /                       |
     mytype                py_objbase<objbase>
       |                           |
py_objbase<mytype>            py_objbase_
       |
   py_mytype
```

So py_objbase_ isn't actually in the inherited classes of py_mytype.  The `static_cast` doesn't know this, so it blindly casts without a runtime check for whether the cast to a derived class is valid.  If you change the `static_cast` to a `dynamic_cast`, you'll get a cast failure:

```C++
            auto *b = dynamic_cast<const py_objbase_*>(&src);
            if (!b) throw std::runtime_error("can't cast to derived py_objbase_!");
            return b->pyprop();
```
results in:
```
RuntimeError: can't cast to derived py_objbase_!
```

So what can you do about this?  There's an example [in the docs](http://pybind11.readthedocs.io/en/master/advanced/classes.html#combining-virtual-functions-and-inheritance): Basically, you need to stick to one alias template class per class, where the the alias hierarchy matches the main class hierarchy (except for the base class argument).

Basically, similar to what you have, except that you need to move the `objbase_` bits into the `py_objbase` so they are actually available to `py_mytype<...>` instances.

The second issue is that you *need* the `py::init_alias`: that forces alias initialization when the type is constructed directly from python.  Without it, the alias is assumed to only provide virtual method overrides, and so is only instantiated when needed: when a class in Python inherits from the bound class.  Otherwise the extra space the alias would need is allocated but uninitialized memory.

But as you pointed out, that segfaults.  My suspicion is that we're doing a `static_cast` (or maybe even a `reinterpret_cast`) on the alias, which is going to fail when the alias uses multiple inheritance.  A fix (or even just tracking this down to a particular `.._cast`) would be welcome, if you want to try to track this down, but it's likely to need some time debugging and poking around in the alias handling code in `pybind11.h`.

There is, however, a relatively easy workaround: you can flatten the multiple inheritance in the alias classes so that they still resolve in the same order, but don't use multiple inheritance within the alias part of the hierarchy.  I've amended your example incorporating both changes (diff first, to see the changes, followed by the whole thing):

```diff
--- example.cpp.orig	2017-04-16 09:27:50.597988804 -0400
+++ example.cpp	2017-04-16 10:31:17.097387913 -0400
@@ -36,26 +36,22 @@
 // trampoline
 template<class T = objbase>
 class py_objbase : public T {
+	double pyprop_ = 42.84;
 public:
 	using T::T;
 
 	std::string name() const override {
 		PYBIND11_OVERLOAD(std::string, T, name);
 	}
-};
-
-class py_objbase_ : public py_objbase<> {
-	double pyprop_ = 42.84;
-
-public:
-	using py_objbase<>::py_objbase;
 
 	double pyprop() const { return pyprop_; }
 };
 
-class py_iface : public iface {
+
+template <class PyNext = iface>
+class py_iface : public PyNext {
 public:
-	using iface::iface;
+	using PyNext::PyNext;
 
 	int f() const override {
 		PYBIND11_OVERLOAD_PURE(int, iface, f);
@@ -63,9 +59,10 @@
 };
 
 // bind mytype
-class py_mytype : public py_iface, public py_objbase<mytype> {
+template <class T = mytype>
+class py_mytype : public py_iface<py_objbase<mytype>> {
 public:
-	using py_objbase<mytype>::py_objbase;
+	using py_iface<py_objbase<mytype>>::py_iface;
 
 	int f() const override {
 		PYBIND11_OVERLOAD(int, mytype, f);
@@ -76,24 +73,24 @@
 	py::module m("example");
 
 	// bind objbase
-	py::class_<objbase, py_objbase_, std::shared_ptr<objbase>>(m, "objbase", py::multiple_inheritance())
+	py::class_<objbase, py_objbase<>, std::shared_ptr<objbase>>(m, "objbase", py::multiple_inheritance())
 		.def(py::init_alias<>())
 		.def("name", &objbase::name)
 		.def_property_readonly("prop", &objbase::prop)
 		.def_property_readonly("refs", [](const objbase& src) { return src.shared_from_this().use_count() - 1; })
-		.def_property_readonly("pyprop", [](const objbase& src) {
-			return static_cast<const py_objbase_*>(&src)->pyprop();
+		.def_property_readonly("pyprop", [](const py_objbase<>& src) {
+			return src.pyprop();
 		})
 	;
 
 	// iface
-	py::class_<iface, py_iface, std::shared_ptr<iface>>(m, "iface", py::multiple_inheritance())
+	py::class_<iface, py_iface<>, std::shared_ptr<iface>>(m, "iface", py::multiple_inheritance())
 		.def("f", &iface::f)
 	;
 
 	// bind mytype
-	py::class_<mytype, iface, objbase, py_mytype, sp_my>(m, "mytype", py::multiple_inheritance())
-		.def(py::init<>())
+	py::class_<mytype, iface, objbase, py_mytype<>, sp_my>(m, "mytype", py::multiple_inheritance())
+		.def(py::init_alias<>())
 		.def("name", &mytype::name)
 		.def("f", &mytype::f)
 		.def_property_readonly("n", [](mytype& src){ return src.n; })
```

full code:
```C++
#include <pybind11/pybind11.h>
#include <iostream>

namespace py = pybind11;
using namespace pybind11::literals;

// classes
class objbase : public std::enable_shared_from_this< objbase > {
	int prop_ = 42;
public:
	virtual std::string name() const {
		return "objbase";
	}

	int prop() const { return prop_; }
};

class iface {
public:
	int n = 42;
	virtual int f() const = 0;
};

class mytype : public iface, public objbase {
public:
	std::string name() const override {
		return "mytype";
	}
	int f() const override {
		return 42;
	}
};
using sp_my = std::shared_ptr<mytype>;
using sp_cmy = std::shared_ptr<const mytype>;

// trampoline
template<class T = objbase>
class py_objbase : public T {
	double pyprop_ = 42.84;
public:
	using T::T;

	std::string name() const override {
		PYBIND11_OVERLOAD(std::string, T, name);
	}

	double pyprop() const { return pyprop_; }
};


template <class PyNext = iface>
class py_iface : public PyNext {
public:
	using PyNext::PyNext;

	int f() const override {
		PYBIND11_OVERLOAD_PURE(int, iface, f);
	}
};

// bind mytype
template <class T = mytype>
class py_mytype : public py_iface<py_objbase<mytype>> {
public:
	using py_iface<py_objbase<mytype>>::py_iface;

	int f() const override {
		PYBIND11_OVERLOAD(int, mytype, f);
	}
};

PYBIND11_PLUGIN(example) {
	py::module m("example");

	// bind objbase
	py::class_<objbase, py_objbase<>, std::shared_ptr<objbase>>(m, "objbase", py::multiple_inheritance())
		.def(py::init_alias<>())
		.def("name", &objbase::name)
		.def_property_readonly("prop", &objbase::prop)
		.def_property_readonly("refs", [](const objbase& src) { return src.shared_from_this().use_count() - 1; })
		.def_property_readonly("pyprop", [](const py_objbase<>& src) {
			return src.pyprop();
		})
	;

	// iface
	py::class_<iface, py_iface<>, std::shared_ptr<iface>>(m, "iface", py::multiple_inheritance())
		.def("f", &iface::f)
	;

	// bind mytype
	py::class_<mytype, iface, objbase, py_mytype<>, sp_my>(m, "mytype", py::multiple_inheritance())
		.def(py::init_alias<>())
		.def("name", &mytype::name)
		.def("f", &mytype::f)
		.def_property_readonly("n", [](mytype& src){ return src.n; })
	;

	return m.ptr();
}
```

Also just for reference, for classes it works like so

```
#include <pybind11/pybind11.h>
#include <pybind11/numpy.h>

namespace py = pybind11;

template <typename T>
class C : public SuperClass
{
 C(int foo)	{}
 void func (int baa)
}

template <typename T>
void C<T> :: func(int baa) {}

PYBIND11_MODULE(example, m) {
py::class_< C<double>, shared_ptr< C<double> >, SuperClass>(m, "C")
 .def(py::init<int>())
 .def("func", &C<double>::func);
}
```

