P.S. I just noticed that I had not pushed the working most recent version of my modified Python3 grammar to the link above. Sorry about that! It's fixed now.

By the way, by adding a postprocessor option to reconstructors (similar to postlexers), I was able to correctly reconstruct Python3 code for the entire standard lib, reparse it, and assert that the reconstructed parse tree is identical to that generated for the original code! Times for initial parsing and reconstruction are still around 1-10 seconds for each standard lib file.

Please do let me know if you would be interested in a pull request for the postprocessor option!

```
import sys
import os, os.path
from io import open
import glob, time
from pprint import pprint

from lark.reconstruct import Reconstructor

from lark import Lark
from lark.indenter import Indenter

# __path__ = os.path.dirname(__file__)

class PythonIndenter(Indenter):
    NL_type = 'NEWLINE'
    OPEN_PAREN_types = ['LPAR', 'LSQB', 'LBRACE']
    CLOSE_PAREN_types = ['RPAR', 'RSQB', 'RBRACE']
    INDENT_type = 'INDENT'
    DEDENT_type = 'DEDENT'
    tab_len = 8

kwargs = dict(rel_to=__file__, postlex=PythonIndenter(), start='file_input')

python_parser3 = Lark.open('C:/Users/jmalar1/PycharmProjects/Lassi/ਲੱਸੀ/Extensions/ਪੈਧਾਨ_੩/ਪੈਧਾਨ ੩.lark',parser='lalr', **kwargs)
def postproc_python3(l):
    for x in l:
        if not hasattr(x, 'type') or not x.type in ['INDENT', 'DEDENT']:
            yield '{} '.format(x) if len(x.strip()) and not x.strip(' \t').endswith('\n') else x

def _read(fn, *args):
    kwargs = {'encoding': 'iso-8859-1'}
    with open(fn, *args, **kwargs) as f:
        return f.read()

def _get_lib_path():
    if os.name == 'nt':
        if 'PyPy' in sys.version:
            return os.path.join(sys.prefix, 'lib-python', sys.winver)
        else:
            return os.path.join(sys.prefix, 'Lib')
    else:
        return [x for x in sys.path if x.endswith('%s.%s' % sys.version_info[:2])][0]

def test_python_lib():

    path = _get_lib_path()

    files = glob.glob(path+'/*.py')
    Recons = Reconstructor(python_parser3)

    start = time.time()

    for f in files:
        print( f , end=" ")
        try:
            # print list(python_parser.lex(_read(os.path.join(path, f)) + '\n'))
            start_file = time.time()
            tree = python_parser3.parse(_read(os.path.join(path, f)) + '\n')
            new = Recons.reconstruct(tree, postproc=postproc_python3)
            print(round(time.time() - start_file, 2))
            assert python_parser3.parse(new) == tree
        except:
            print ('At %s' % f)
            raise

    end = time.time()
    print( "test_python_lib (%d files), time: %s secs"%(len(files), end-start) )


if __name__ == '__main__':
    test_python_lib()
```
